  'router.use(cspMw);',
  '// In a template, render res.locals.cspNonce into <script nonce="...">.</code></pre>',

  '<h2 id="body-parser">Body parser</h2>',

  '<h3>b.middleware.bodyParser(opts?) <a class="anchor" href="#body-parser">#</a></h3>',
