  '<h2 id="api-encrypt">API encryption</h2>',

  '<h3>b.middleware.apiEncrypt(opts) <a class="anchor" href="#api-encrypt-call">#</a></h3>',
  '<pre><code class="language-javascript">{',
  '  keypair:              { publicKey, privateKey, ecPublicKey, ecPrivateKey },',
  '  // OR for rotation overlap (active first; older keypairs follow):',
  '  keypairs:             [keypair, prevKeypair],',
  '  // ---- replay defense ----',
  '  replayWindowMs:       number,                  // default: 5 minutes',
  '  nonceStore:           b.nonceStore,            // default: in-memory; cluster-shared for multi-replica',
  '  pruneIntervalMs:      number,                  // default: max(30s, replayWindowMs/2)',
  '  // ---- routing ----',
  '  exemptPaths:          [string | RegExp],       // exact + prefix match for strings; RegExp test',
