  '//   replayWindowMs: b.constants.TIME.minutes(5),',
  '//   nonceStore:     b.nonceStore.create({ backend: "cluster" }),',
  '// });',
  '//',
  '// Per-session mode — opt in for high-throughput chat / streaming / mobile.',
  '// var apiEncrypt = b.middleware.apiEncrypt({',
  '//   keypair:             keypair,',
  '//   keying:              "per-session",',
  '//   sessionTtlMs:        b.constants.TIME.minutes(15),',
  '//   sessionMaxResponses: 1024,',
  '//   sessionStore:        b.cache.create({ backend: "cluster" }),',
  '//   observability:       b.observability,',
  '// });',
  '// router.use(apiEncrypt);',
  '//',
  '// Client side — same shape, opt into per-session via the keying field.',
  '// var enc = b.middleware.apiEncrypt.client({',
  '//   pubkey: callee.pubkey,',
  '//   keying: "per-session",',
  '// });',
  '// var first  = enc.encryptRequest({ user: "alice" });   // bootstrap envelope',
  '// var second = enc.encryptRequest({ msg:  "hello" });   // sid + counter only',
  '// // After the server returns 401 session-expired, call enc.resetSession()',
  '// // and re-issue.',
  '//',
  '// Server-to-server with the framework HTTP client:',
  '// var encClient = b.httpClient.encrypted({',
  '//   pubkey:  callee.pubkey,',
  '//   baseUrl: "https://callee.example",',
  '//   keying:  "per-session",',
